import { BoardEntity } from '../../../board-entity';
import { CardIds } from '../../../services/card-ids';
import { magnetizeToTarget, OnAfterMagnetizeInput } from '../../../simulation/magnetize';
import { OnAfterMagnetizeCard } from '../../card.interface';

export const PolarizingBeatboxer: OnAfterMagnetizeCard = {
	cardIds: [CardIds.PolarizingBeatboxer_BG26_149, CardIds.PolarizingBeatboxer_BG26_149_G],
	onAfterMagnetize: (entity: BoardEntity, input: OnAfterMagnetizeInput) => {
		if (PolarizingBeatboxer.cardIds.includes(input.source.cardId)) {
			return;
		}
		const mult = entity.cardId === CardIds.PolarizingBeatboxer_BG26_149_G ? 2 : 1;
		for (let i = 0; i < mult; i++) {
			magnetizeToTarget(
				[entity],
				entity,
				[input.magnetizedCard],
				input.board,
				input.hero,
				input.otherBoard,
				input.otherHero,
				input.gameState,
				// Don't retrigger effects that say "the first time you magnetize this"
				false,
			);
			input.gameState.spectator.registerPowerTarget(
				entity,
				input.magnetizeTarget,
				input.board,
				input.hero,
				input.otherHero,
			);
		}
	},
};
